import numpy as np
from collections import deque
import random

class DynaQ:
    """Tabular Dyna-Q for discrete state-action spaces."""
    def __init__(self, n_states, n_actions, alpha=0.1, gamma=0.95, k=10):
        self.Q = np.zeros((n_states, n_actions))
        self.model = {}          # (s, a) -> (r, s') transitions
        self.alpha = alpha
        self.gamma = gamma
        self.k = k               # imagined updates per real step
        self.seen = []           # list of (s, a) pairs seen so far

    def update(self, s, a, r, s_next):
        # 1. Real Q-update
        td = r + self.gamma * self.Q[s_next].max() - self.Q[s, a]
        self.Q[s, a] += self.alpha * td

        # 2. Model update
        self.model[(s, a)] = (r, s_next)
        if (s, a) not in self.seen:
            self.seen.append((s, a))

        # 3. K imagined updates from stored model
        for _ in range(self.k):
            s_sim, a_sim = random.choice(self.seen)
            r_sim, s_sim_next = self.model[(s_sim, a_sim)]
            td_sim = r_sim + self.gamma * self.Q[s_sim_next].max() - self.Q[s_sim, a_sim]
            self.Q[s_sim, a_sim] += self.alpha * td_sim

    def act(self, s, epsilon=0.1):
        if np.random.rand() < epsilon:
            return np.random.randint(self.Q.shape[1])
        return int(self.Q[s].argmax())
